#!/usr/bin/env node
let fs=require("fs"),path=require("path"),promisify=require("util").promisify,readFile=promisify(fs.readFile),writeFile=promisify(fs.writeFile),mkdir=promisify(fs.mkdir),copyFile=promisify(fs.copyFile),config={languages:[{code:"en",name:"English",dir:"ltr"},{code:"es",name:"Español",dir:"ltr"},{code:"fr",name:"Français",dir:"ltr"},{code:"ar",name:"العربية",dir:"rtl"}],defaultLanguage:"en",baseUrl:"https://divinci.ai",rootDir:path.resolve(__dirname,"..")};function generateHreflangTags(e){var a,i=[];i.push(`<link rel="alternate" href="${config.baseUrl}/${e}" hreflang="x-default" />`);for(a of config.languages){var t=a.code===config.defaultLanguage?e:a.code+"/"+e;i.push(`<link rel="alternate" href="${config.baseUrl}/${t}" hreflang="${a.code}" />`)}return i.join("\n    ")}async function createLanguageDirectory(a){if(a!==config.defaultLanguage){var e=path.join(config.rootDir,a);try{await mkdir(e,{recursive:!0}),console.log("✅ Created directory for "+a)}catch(e){"EEXIST"!==e.code&&console.error(`❌ Error creating directory for ${a}:`,e.message)}}}async function createLanguageIndex(a,i,t,r){try{let e=r.replace(/<html lang="en"/,`<html lang="${a}" dir="${t}"`).replace(/<title>Divinci™ Multiplayer AI Chat<\/title>/,`<title>Divinci™ Multiplayer AI Chat - ${i}</title>`);var n=generateHreflangTags("index.html"),o=(e=(e=e.replace(/<meta name="viewport" content="width=device-width, initial-scale=1.0" \/>/,`<meta name="viewport" content="width=device-width, initial-scale=1.0" />

    <!-- Hreflang tags for language alternatives -->
    `+n)).replace(/<\/head>/,`    <!-- Set default language -->
    <script>
        document.addEventListener('DOMContentLoaded', function() {
            if (window.i18n && window.i18n.changeLanguage) {
                window.i18n.changeLanguage('${a}');
            }
        });
    </script>
</head>`),a!==config.defaultLanguage&&(e=e.replace(/href="(?!http|\/\/|#)([^"]+)"/g,(e,a)=>a.startsWith("#")||a.startsWith("http")||a.startsWith("//")?e:`href="../${a}"`).replace(/src="(?!http|\/\/|#)([^"]+)"/g,(e,a)=>a.startsWith("#")||a.startsWith("http")||a.startsWith("//")?e:`src="../${a}"`).replace(/data-include="([^"]+)"/g,(e,a)=>`data-include="../${a}"`)),a===config.defaultLanguage?path.join(config.rootDir,"index.html"):path.join(config.rootDir,a,"index.html"));await writeFile(o,e,"utf8"),console.log(`✅ Created ${a} version of index.html`)}catch(e){console.error(`❌ Error creating ${a} version of index.html:`,e.message)}}async function addHreflangToAllPages(){console.log("⚠️ Adding hreflang tags to all HTML files is not implemented yet.")}async function main(){try{console.log("🚀 Generating language-specific pages...");var e,a,i=path.join(config.rootDir,"index.html"),t=await readFile(i,"utf8");for(e of config.languages)await createLanguageDirectory(e.code);for(a of config.languages)await createLanguageIndex(a.code,a.name,a.dir,t);await addHreflangToAllPages(),console.log("🎉 Language-specific pages generated successfully!")}catch(e){console.error("❌ Error generating language-specific pages:",e.message),process.exit(1)}}main();